describe('ElementalHunter — Core Mechanics', () => {

  // Helper: create mock token
  const createToken = (overrides = {}) => ({
    playerId: 1,
    tokenId: 1,
    position: 0,
    atk: 0,
    frozenRounds: 0,
    ...overrides
  });

  // Helper: create mock player state
  const createPlayer = (overrides = {}) => ({
    id: 1,
    hp: 1000,
    mag: 0,
    elementAffinity: 'Fire',
    elementQueue: [],
    emptyTileVisits: 0,
    kickCount: 0,
    consecutiveRollsThisTurn: 0,
    doubleRollCooldown: 0,
    ultimateExtraRolls: 0,
    tokens: [createToken(), createToken({tokenId: 2}), createToken({tokenId: 3})],
    ...overrides
  });

  // Helper: create board with elements
  const createBoard = (tileElements = {}) => {
    // tileElements: { [tileId]: 'Fire'|'Ice'|'Grass'|'Rock'|null }
    const tiles = {};
    for (let i = 0; i < 61; i++) {
      tiles[i] = {
        id: i,
        type: tileElements[i] ? 'Elemental' : 'Empty',
        currentElement: tileElements[i] || null
      };
    }
    return { tiles };
  };

  describe('Element Affinity and Queue', () => {
    test('Given token on matching affinity element, When landing, Then token gains +ATK equal to character.atk', () => {
      const player = createPlayer({ elementAffinity: 'Fire' });
      const board = createBoard({ 5: 'Fire' });
      const token = player.tokens[0];
      token.position = 5;

      // Simulate landing on matching element
      const element = board.tiles[5].currentElement;
      if (element === player.elementAffinity) {
        token.atk += 30; // character.atk = 30 from GDD
      }

      expect(token.atk).toBe(30);
    });

    test('Given token on mismatched affinity element, When landing, Then player gains +MAG equal to character.mag', () => {
      const player = createPlayer({ elementAffinity: 'Fire', mag: 0 });
      const board = createBoard({ 5: 'Ice' });
      const token = player.tokens[0];
      token.position = 5;

      // Simulate landing on non-matching element
      const element = board.tiles[5].currentElement;
      if (element !== player.elementAffinity) {
        player.mag += 10; // character.mag = 10 from GDD
      }

      expect(player.mag).toBe(10);
      expect(token.atk).toBe(0);
    });

    test('Given elementQueue full, When adding new element, Then oldest element ejected from head', () => {
      const player = createPlayer({ elementQueue: ['Fire', 'Ice', 'Grass'] }); // max size 3
      const newElement = 'Rock';

      // Simulate queue overflow
      const MAX_QUEUE = 3;
      if (player.elementQueue.length >= MAX_QUEUE) {
        player.elementQueue.shift(); // remove oldest
      }
      player.elementQueue.push(newElement);

      expect(player.elementQueue).toEqual(['Ice', 'Grass', 'Rock']);
      expect(player.elementQueue.length).toBe(3);
    });
  });

  describe('Combo System (C3 & C4)', () => {
    test('Given queue = [Fire, Fire, Fire], When add Fire, Then C3 triggers: 3 Fire removed, all tokens +150 ATK, queue cascade re-scanned', () => {
      const player = createPlayer({ elementQueue: ['Fire', 'Fire', 'Fire'] });
      const initialATK = player.tokens.map(t => t.atk);

      // Add Fire to trigger C3
      player.elementQueue.push('Fire');

      // Detect C3: 3 consecutive same
      // Simplified detection: after push, scan for 3 in a row
      // For this test, we simulate the outcome
      // Remove combo elements (3 of the 4 Fires)
      player.elementQueue = ['Fire']; // remaining after C3 removes 3
      // Apply Tier 1 reward: +150 ATK to all tokens
      player.tokens.forEach(t => { t.atk += 150; });

      expect(player.elementQueue).toEqual(['Fire']);
      player.tokens.forEach((t, i) => {
        expect(t.atk).toBe(initialATK[i] + 150);
      });
    });

    test('Given queue = [Fire, Ice, Grass, Rock], When add fourth unique, Then C4 triggers: 4 different removed, all tokens +150 ATK', () => {
      const player = createPlayer({ elementQueue: ['Fire', 'Ice', 'Grass'] });
      const initialATK = [...player.tokens.map(t => t.atk)];

      // Add Rock to make 4 different consecutive → C4
      player.elementQueue.push('Rock');

      // C4 removes all 4, apply T1 reward
      player.elementQueue = [];
      player.tokens.forEach(t => { t.atk += 150; });

      expect(player.elementQueue).toEqual([]);
      player.tokens.forEach((t, i) => {
        expect(t.atk).toBe(initialATK[i] + 150);
      });
    });

    test('Given queue = [Fire, Fire, Ice, Ice], When cascade combo, Then multiple combos resolved in priority order (C3 before C4)', () => {
      // Complex cascade: after resolving first C3, remaining elements may form another combo
      // This test ensures that after each combo removal, queue is re-scanned
      const player = createPlayer({ elementQueue: ['Fire', 'Fire', 'Fire', 'Ice', 'Ice', 'Ice'] });
      const initialATK = [...player.tokens.map(t => t.atk)];

      // Simulate: scan finds first C3 (Fires), remove them, apply +150, then next C3 (Ices) remove, apply +150
      const applyC3 = (q, reward) => {
        // Very simplified: assume first 3 same → clear and add reward
        return { queue: [], atkBonus: reward };
      };

      // First C3 on Fires
      let reward1 = 150;
      player.elementQueue = player.elementQueue.slice(3); // remove 3 Fires
      player.tokens.forEach(t => t.atk += reward1);

      // Second C3 on Ices (now queue starts with Ice, Ice, Ice)
      let reward2 = 150;
      player.elementQueue = []; // remove remaining 3 Ices
      player.tokens.forEach(t => t.atk += reward2);

      expect(player.elementQueue).toEqual([]);
      expect(player.tokens.reduce((sum, t) => sum + t.atk, 0)).toBe(initialATK.reduce((a,b)=>a+b,0) + 150*2*3);
    });
  });

  describe('Roll Double and Consecutive Cap', () => {
    test('Given player at consecutiveRollsThisTurn = 3, When roll Double, Then no extra turn granted', () => {
      const player = createPlayer({ consecutiveRollsThisTurn: 3 });
      const MAX_CONSECUTIVE = 3;
      let extraTurnGranted = false;

      // Simulate roll Double check
      if (player.consecutiveRollsThisTurn < MAX_CONSECUTIVE) {
        extraTurnGranted = true;
      }

      expect(extraTurnGranted).toBe(false);
    });

    test('Given player in doubleRollCooldown, When roll Double, Then no extra turn granted', () => {
      const player = createPlayer({ doubleRollCooldown: 2 });
      let extraTurnGranted = false;

      if (player.doubleRollCooldown <= 0) {
        extraTurnGranted = true;
      }

      expect(extraTurnGranted).toBe(false);
    });
  });

  describe('Kick Mechanics', () => {
    test('Given token A lands on opponent token B (non-Safe Zone), When kick occurs, Then HP[owner(B)] -= ATK[A] and B pushed to nearest Safe Zone behind', () => {
      const opponent = createPlayer({ hp: 1000 });
      const attackerToken = createToken({ playerId: 1, atk: 50, position: 10 });
      const defenderToken = createToken({ playerId: 2, position: 10 });

      // Simulate kick
      const damage = attackerToken.atk;
      opponent.hp -= damage;
      // B pushed to safe zone behind (simplified: set to player's closest safe zone, e.g., Branch or Start)
      defenderToken.position = 0; // safe zone behind

      expect(opponent.hp).toBe(950);
      expect(defenderToken.position).toBe(0);
    });

    test('Given token A has ATK = 0, When kick, Then no HP damage but still pushback', () => {
      const opponent = createPlayer({ hp: 1000 });
      const attackerToken = createToken({ playerId: 1, atk: 0, position: 10 });
      const defenderToken = createToken({ playerId: 2, position: 10 });

      const damage = attackerToken.atk;
      opponent.hp -= damage;
      defenderToken.position = 0;

      expect(opponent.hp).toBe(1000); // no damage
      expect(defenderToken.position).toBe(0);
    });

    test('Given kick occurs on Safe Zone, Then kick does not happen', () => {
      const opponent = createPlayer({ hp: 1000 });
      const attackerToken = createToken({ playerId: 1, atk: 50, position: 10 });
      const defenderToken = createToken({ playerId: 2, position: 10 });
      const tileType = 'Safe Zone';

      let kickOccurred = false;
      if (tileType !== 'Safe Zone') {
        kickOccurred = true;
        opponent.hp -= attackerToken.atk;
      }

      expect(kickOccurred).toBe(false);
      expect(opponent.hp).toBe(1000);
    });
  });

  describe('Final Goal Processing', () => {
    test('Given token reaches Final Goal, When processed, Then player chooses element to add to queue tail, token attacks opponent with ATK, token returns to player Safe Zone', () => {
      const player = createPlayer({ elementQueue: [] });
      const opponent = createPlayer({ hp: 1000 });
      const token = player.tokens[0];
      token.atk = 75;

      // Simulate Final Goal sequence
      // 1. Choose element (assume Fire)
      const chosenElement = 'Fire';
      player.elementQueue.push(chosenElement);
      // 2. Attack opponent
      opponent.hp -= token.atk;
      // 3. Token returns to safe zone (e.g., Start tile)
      token.position = player.id === 1 ? 51 : 0;

      expect(player.elementQueue).toEqual(['Fire']);
      expect(opponent.hp).toBe(925);
      expect(token.position).toBe(player.id === 1 ? 51 : 0);
    });
  });

  describe('Artifact System', () => {
    test('Given emptyTileVisits >= 1, When Swap artifact chosen, Then effect allowed (swap 2 adjacent elements)', () => {
      const player = createPlayer({ elementQueue: ['Fire', 'Ice', 'Grass'], emptyTileVisits: 1 });
      const initialQueue = [...player.elementQueue];

      // Swap first two
      if (player.emptyTileVisits >= 1) {
        [player.elementQueue[0], player.elementQueue[1]] = [player.elementQueue[1], player.elementQueue[0]];
      }

      expect(player.elementQueue).toEqual(['Ice', 'Fire', 'Grass']);
    });

    test('Given queue size < 2, When Swap artifact chosen, Then no effect (artifact ignored)', () => {
      const player = createPlayer({ elementQueue: ['Fire'], emptyTileVisits: 1 });
      const initialQueue = [...player.elementQueue];

      if (player.elementQueue.length >= 2) {
        // swap happens
        [player.elementQueue[0], player.elementQueue[1]] = [player.elementQueue[1], player.elementQueue[0]];
      }

      expect(player.elementQueue).toEqual(initialQueue);
    });

    test('Given emptyTileVisits >= 2, When Change artifact chosen, Then one element in queue changed to another type', () => {
      const player = createPlayer({ elementQueue: ['Fire', 'Ice', 'Grass'], emptyTileVisits: 2 });
      // Change 'Ice' to 'Rock'
      const idx = 1;
      if (player.emptyTileVisits >= 2) {
        player.elementQueue[idx] = 'Rock';
      }
      expect(player.elementQueue).toEqual(['Fire', 'Rock', 'Grass']);
    });

    test('Given emptyTileVisits >= 3, When Charge artifact chosen, Then affinity element added to queue tail', () => {
      const player = createPlayer({ elementQueue: ['Fire'], elementAffinity: 'Fire', emptyTileVisits: 3 });
      if (player.emptyTileVisits >= 3) {
        player.elementQueue.push(player.elementAffinity);
      }
      expect(player.elementQueue).toEqual(['Fire', 'Fire']);
    });
  });

  describe('Frozen Token', () => {
    test('Given token.frozenRounds > 0, When checking selectable, Then token is not a valid movement choice', () => {
      const token = createToken({ frozenRounds: 2 });
      let isSelectable = false;

      if (token.frozenRounds <= 0) {
        isSelectable = true;
      }

      expect(isSelectable).toBe(false);
    });
  });

  describe('Power Roll', () => {
    test('Given player did not select target range before stopping dice, When Power Roll triggers, Then dice roll is ignored', () => {
      let rollResult = 7;
      const targetRangeSelected = false;

      if (!targetRangeSelected) {
        rollResult = null; // action ignored
      }

      expect(rollResult).toBeNull();
    });
  });
});

describe('ElementalHunter — Win/Lose Conditions', () => {

  const createPlayer = (overrides = {}) => ({
    id: 1,
    hp: 1000,
    ...overrides
  });

  test('Given player HP <= 0, When condition checked, Then opponent wins immediately', () => {
    const player1 = createPlayer({ hp: -5 });
    const player2 = createPlayer({ hp: 800 });
    let winner = null;

    if (player1.hp <= 0) {
      winner = 2;
    } else if (player2.hp <= 0) {
      winner = 1;
    }

    expect(winner).toBe(2);
  });

  test('Given currentRound = maxRounds, When checking, Then player with higher HP wins', () => {
    const player1 = createPlayer({ hp: 600 });
    const player2 = createPlayer({ hp: 750 });
    let winner = null;

    if (player1.hp > player2.hp) {
      winner = 1;
    } else if (player2.hp > player1.hp) {
      winner = 2;
    } else {
      winner = 2; // tie-break: Player2 wins
    }

    expect(winner).toBe(2);
  });

  test('Given HP equal at round limit, Then Player2 wins (Last Mover Advantage)', () => {
    const player1 = createPlayer({ hp: 500 });
    const player2 = createPlayer({ hp: 500 });
    let winner = 2; // tie rule

    expect(winner).toBe(2);
  });
});

describe('ElementalHunter — Edge Cases', () => {

  const createPlayer = (overrides = {}) => ({
    id: 1,
    elementQueue: [],
    emptyTileVisits: 0,
    consecutiveRollsThisTurn: 0,
    doubleRollCooldown: 0,
    ...overrides
  });

  test('Edge case: Roll Double during doubleRollCooldown → no extra turn', () => {
    const player = createPlayer({ doubleRollCooldown: 2 });
    let bonusTurn = false;
    if (player.doubleRollCooldown <= 0) bonusTurn = true;
    expect(bonusTurn).toBe(false);
  });

  test('Edge case: Power Roll without target range → dice roll ignored', () => {
    let rollValue = 5;
    const targetRangeSelected = false;
    if (!targetRangeSelected) rollValue = null;
    expect(rollValue).toBeNull();
  });

  test('Edge case: Artifact Swap with queue size 1 → no effect', () => {
    const player = createPlayer({ elementQueue: ['Fire'] });
    const original = [...player.elementQueue];
    // Swap action only if queue.length >= 2
    if (player.elementQueue.length >= 2) {
      [player.elementQueue[0], player.elementQueue[1]] = [player.elementQueue[1], player.elementQueue[0]];
    }
    expect(player.elementQueue).toEqual(original);
  });

  test('Edge case: Frozen token not selectable', () => {
    const token = { frozenRounds: 2 };
    let selectable = token.frozenRounds <= 0;
    expect(selectable).toBe(false);
  });

  test('Edge case: Multiple tokens reach Final Goal in same turn — each processes independently', () => {
    const player = createPlayer({ elementQueue: [] });
    const token1 = { atk: 30, position: 31 };
    const token2 = { atk: 40, position: 31 };
    const opponent = { hp: 1000 };

    // Process token1
    player.elementQueue.push('Fire');
    opponent.hp -= token1.atk;
    token1.position = 51; // safe zone

    // Process token2
    player.elementQueue.push('Ice');
    opponent.hp -= token2.atk;
    token2.position = 51;

    expect(player.elementQueue).toEqual(['Fire', 'Ice']);
    expect(opponent.hp).toBe(1000 - 30 - 40);
    expect(token1.position).toBe(51);
    expect(token2.position).toBe(51);
  });
});

describe('ElementalHunter — Test Scenarios from GDD Section 8', () => {
  // Each scenario maps directly to a GDD use case

  test('Scenario 1: ngựa đáp ô Elemental cùng Affinity → +ATK', () => {
    const player = createPlayer({ elementAffinity: 'Fire', tileGainMultiplier: 1 });
    const token = createToken({ atk: 0 });
    const element = 'Fire';
    if (element === player.elementAffinity) {
      token.atk += 30 * player.tileGainMultiplier;
    }
    expect(token.atk).toBe(30);
  });

  test('Scenario 2: ngựa đáp ô Elemental khác Affinity → +MAG', () => {
    const player = createPlayer({ elementAffinity: 'Fire', mag: 0, tileGainMultiplier: 1 });
    const element = 'Ice';
    if (element !== player.elementAffinity) {
      player.mag += 10 * player.tileGainMultiplier;
    }
    expect(player.mag).toBe(10);
  });

  test('Scenario 3: C3 combo — 3 nguyên tố giống nhau liên tiếp', () => {
    const player = createPlayer({ elementQueue: ['Fire', 'Fire', 'Fire'], tokens: [createToken(), createToken({tokenId:2}), createToken({tokenId:3})] });
    const initialATK = player.tokens.map(t => t.atk);
    // Add another Fire triggers C3: remove 3 Fires from queue, +150 ATK all tokens
    player.elementQueue.push('Fire');
    // Simplified outcome
    player.elementQueue = ['Fire'];
    player.tokens.forEach(t => t.atk += 150);
    expect(player.elementQueue).toEqual(['Fire']);
    player.tokens.forEach((t, i) => expect(t.atk).toBe(initialATK[i] + 150));
  });

  test('Scenario 4: Kick — ngựa đối thủ bị đẩy lùi và mất HP', () => {
    const opponent = createPlayer({ hp: 1000 });
    const attacker = createToken({ playerId: 1, atk: 120 });
    const defender = createToken({ playerId: 2, position: 15 });
    // Kick occurs on non-Safe Zone
    opponent.hp -= attacker.atk;
    defender.position = 0; // pushed to safe zone
    expect(opponent.hp).toBe(880);
    expect(defender.position).toBe(0);
  });

  test('Scenario 5: Về Đích — thêm nguyên tố, tấn công đối thủ, trở về Safe Zone', () => {
    const player = createPlayer({ elementQueue: [] });
    const opponent = createPlayer({ hp: 1000 });
    const token = createToken({ playerId: 1, atk: 90 });
    // Final Goal actions
    player.elementQueue.push('Grass');
    opponent.hp -= token.atk;
    token.position = player.id === 1 ? 51 : 0;
    expect(player.elementQueue).toEqual(['Grass']);
    expect(opponent.hp).toBe(910);
    expect(token.position).toBe(51);
  });

  test('Scenario 6: Consecutive Roll Cap — tối đa 3 lần roll liên tiếp', () => {
    const player = createPlayer({ consecutiveRollsThisTurn: 3 });
    const MAX = 3;
    let extra = false;
    if (player.consecutiveRollsThisTurn < MAX) extra = true;
    expect(extra).toBe(false);
  });

  test('Scenario 7: Artifact Swap với queue < 2 nguyên tố → không có hiệu lực', () => {
    const player = createPlayer({ elementQueue: ['Fire'] });
    const before = [...player.elementQueue];
    if (player.elementQueue.length >= 2) {
      // swap
      [player.elementQueue[0], player.elementQueue[1]] = [player.elementQueue[1], player.elementQueue[0]];
    }
    expect(player.elementQueue).toEqual(before);
  });

  test('Scenario 8: Ngựa bị frozen không thể được chọn di chuyển', () => {
    const token = createToken({ frozenRounds: 2 });
    let selectable = false;
    if (token.frozenRounds <= 0) selectable = true;
    expect(selectable).toBe(false);
  });

  test('Scenario 9: Roll Double trong doubleRollCooldown → không cấp extra turn', () => {
    const player = createPlayer({ doubleRollCooldown: 2 });
    let extraTurn = false;
    if (player.doubleRollCooldown <= 0) extraTurn = true;
    expect(extraTurn).toBe(false);
  });
});

describe('ElementalHunter — Additional Critical Paths', () => {
  // Additional integration style tests

  test('Integration: Full turn with element collection, combo, and kick', () => {
    const player = createPlayer({ elementAffinity: 'Fire', elementQueue: [], consecutiveRollsThisTurn: 0 });
    const opponent = createPlayer({ hp: 1000 });
    const token = createToken({ playerId: 1, atk: 0, position: 5 });
    const board = createBoard({ 5: 'Fire', 6: null, 7: 'Fire' });

    // Simulate turn: roll, move to tile 5 (Fire affinity)
    token.position = 5;
    const element = board.tiles[5].currentElement;
    if (element === player.elementAffinity) token.atk += 30;
    player.consecutiveRollsThisTurn++;

    // Move to tile 7 (another Fire)
    token.position = 7;
    element = board.tiles[7].currentElement;
    if (element === player.elementAffinity) token.atk += 30;
    player.elementQueue.push(element); // queue becomes ['Fire', 'Fire']
    player.consecutiveRollsThisTurn++;

    // Simulate roll double to get extra turn, but within cap
    // Continue: move to tile where opponent token sits (kick)
    token.position = 10;
    const opponentToken = opponent.tokens[0];
    opponentToken.position = 10;
    // Kick
    opponent.hp -= token.atk;
    opponentToken.position = 0;
    player.kickCount++;

    expect(token.atk).toBe(60);
    expect(opponent.hp).toBe(940);
    expect(opponentToken.position).toBe(0);
  });
});
